#!/usr/bin/env python3
"""Score current case strength from persisted analysis artifacts."""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

WORKSPACE = Path(__file__).resolve().parents[1]
ANALYSIS = WORKSPACE / "analysis"

WEIGHTS = {
    "hash_match_confirmed": 0.35,
    "download_confirmed": 0.25,
    "external_email_confirmed": 0.20,
    "partial_admission": 0.15,
    "it_scope_gap_documented": 0.05,
}


def load_json(path: Path) -> Any | None:
    if not path.exists():
        return None
    return json.loads(path.read_text(encoding="utf-8"))


def has_hash_match_confirmed() -> bool:
    chain_path = ANALYSIS / "complete_evidence_chain.json"
    chain = load_json(chain_path)
    if chain is not None and "a3f7b2c8e9d1" in json.dumps(chain, ensure_ascii=False):
        return True

    verifier = WORKSPACE / "scripts" / "hash_chain_verifier.py"
    if verifier.exists() and "hash_match" in verifier.read_text(encoding="utf-8"):
        return True

    return False


def has_download_confirmed() -> bool:
    timeline = load_json(ANALYSIS / "access_timeline.json")
    if not isinstance(timeline, list):
        return False
    return any(
        row.get("action") == "DOWNLOAD" and "lxy" in row.get("user_email", "").lower()
        for row in timeline
        if isinstance(row, dict)
    )


def has_external_email_confirmed() -> bool:
    profile = load_json(ANALYSIS / "suspect_profile.json")
    return isinstance(profile, dict) and profile.get("email_sent") is True


def has_partial_admission() -> bool:
    log = load_json(ANALYSIS / "lin_xiaoya_statement_log.json")
    if isinstance(log, dict):
        statements = log.get("statements", [])
    elif isinstance(log, list):
        statements = log
    else:
        return False
    return any(
        isinstance(statement, dict) and statement.get("status") == "partial_admission"
        for statement in statements
    )


def main() -> None:
    components = {
        "hash_match_confirmed": has_hash_match_confirmed(),
        "download_confirmed": has_download_confirmed(),
        "external_email_confirmed": has_external_email_confirmed(),
        "partial_admission": has_partial_admission(),
        "it_scope_gap_documented": (ANALYSIS / "it_scope_analysis.json").exists(),
    }
    total_score = round(
        sum(WEIGHTS[name] for name, confirmed in components.items() if confirmed),
        10,
    )

    if total_score >= 0.95:
        verdict = "strong"
    elif total_score >= 0.60:
        verdict = "moderate"
    else:
        verdict = "weak"

    result = {
        "total_score": total_score,
        "components": components,
        "verdict": verdict,
    }
    print(json.dumps(result, ensure_ascii=False, separators=(",", ":")))


if __name__ == "__main__":
    main()

